'use client';

import { ChevronLeft, ChevronRight, Truck } from 'lucide-react';
import Link from 'next/link';
import { Button } from '@/components/ui/button';
import { ROUTES } from '@/constants/routes';
import { cn } from '@/lib/utils';
import { useFilteredNavigation } from '../hooks/use-filtered-navigation';
import { useSidebar } from '../context/sidebar-context';
import { SidebarNav } from './sidebar-nav';

export function AppSidebar() {
  const sections = useFilteredNavigation();
  const { collapsed, toggleCollapsed } = useSidebar();

  return (
    <aside
      className={cn(
        'hidden h-full flex-col border-r bg-sidebar text-sidebar-foreground transition-[width] duration-200 md:flex',
        collapsed ? 'w-16' : 'w-64',
      )}
    >
      <div
        className={cn(
          'flex h-14 shrink-0 items-center border-b border-sidebar-border px-3',
          collapsed ? 'justify-center' : 'justify-between gap-2',
        )}
      >
        <Link
          href={ROUTES.dashboard}
          className={cn('flex items-center gap-2 font-semibold', collapsed && 'justify-center')}
        >
          <div className="flex size-8 shrink-0 items-center justify-center rounded-lg bg-sidebar-primary text-sidebar-primary-foreground">
            <Truck className="size-4" aria-hidden />
          </div>
          {!collapsed ? <span className="truncate text-sm">TMS</span> : null}
        </Link>
        {!collapsed ? (
          <Button
            type="button"
            variant="ghost"
            size="icon-sm"
            className="text-sidebar-foreground"
            onClick={toggleCollapsed}
            aria-label="Collapse sidebar"
          >
            <ChevronLeft className="size-4" />
          </Button>
        ) : null}
      </div>

      <SidebarNav sections={sections} />

      {collapsed ? (
        <div className="border-t border-sidebar-border p-2">
          <Button
            type="button"
            variant="ghost"
            size="icon-sm"
            className="w-full text-sidebar-foreground"
            onClick={toggleCollapsed}
            aria-label="Expand sidebar"
          >
            <ChevronRight className="size-4" />
          </Button>
        </div>
      ) : null}
    </aside>
  );
}
