'use client';

import { Bell } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { findNavigationItemByPath } from '@/constants/navigation';
import { usePathname } from 'next/navigation';
import { AppBreadcrumbs } from './app-breadcrumbs';
import { MobileSidebar } from './mobile-sidebar';
import { ThemeToggle } from './theme-toggle';
import { UserMenu } from './user-menu';

export function TopNavbar() {
  const pathname = usePathname();
  const currentNav = findNavigationItemByPath(pathname);

  return (
    <header className="sticky top-0 z-30 flex h-14 shrink-0 items-center gap-4 border-b bg-background/95 px-4 backdrop-blur supports-[backdrop-filter]:bg-background/80 lg:px-6">
      <MobileSidebar />

      <div className="flex min-w-0 flex-1 flex-col gap-0.5">
        <h2 className="truncate text-sm font-semibold md:hidden">
          {currentNav?.label ?? 'TMS'}
        </h2>
        <AppBreadcrumbs />
      </div>

      <div className="flex items-center gap-2">
        <Button
          type="button"
          variant="outline"
          size="icon-sm"
          disabled
          aria-label="Notifications (coming soon)"
        >
          <Bell className="size-4" />
        </Button>
        <ThemeToggle />
        <UserMenu />
      </div>
    </header>
  );
}
