'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from '@/components/ui/tooltip';
import { cn } from '@/lib/utils';
import type { NavigationItem, NavigationSection } from '@/constants/navigation';
import { useSidebar } from '../context/sidebar-context';

function isNavItemActive(pathname: string, href: string): boolean {
  if (href === '/dashboard') {
    return pathname === href;
  }

  return pathname === href || pathname.startsWith(`${href}/`);
}

interface SidebarNavProps {
  sections: NavigationSection[];
  onNavigate?: () => void;
}

function NavLink({
  item,
  collapsed,
  active,
  onNavigate,
}: {
  item: NavigationItem;
  collapsed: boolean;
  active: boolean;
  onNavigate?: () => void;
}) {
  const Icon = item.icon;
  const content = (
    <>
      <Icon className="size-4 shrink-0" aria-hidden />
      {!collapsed ? (
        <>
          <span className="truncate">{item.label}</span>
          {item.comingSoon ? (
            <Badge variant="secondary" className="ml-auto text-[10px]">
              Soon
            </Badge>
          ) : null}
        </>
      ) : null}
    </>
  );

  const className = cn(
    'flex w-full items-center gap-3 rounded-lg px-3 py-2 text-sm font-medium transition-colors',
    active
      ? 'bg-sidebar-accent text-sidebar-accent-foreground'
      : 'text-sidebar-foreground/80 hover:bg-sidebar-accent/60 hover:text-sidebar-accent-foreground',
    item.comingSoon && 'opacity-70',
    collapsed && 'justify-center px-2',
  );

  if (item.comingSoon) {
    const disabled = (
      <span className={cn(className, 'cursor-not-allowed')} aria-disabled>
        {content}
      </span>
    );

    if (collapsed) {
      return (
        <Tooltip>
          <TooltipTrigger render={disabled} />
          <TooltipContent side="right">{item.label} (coming soon)</TooltipContent>
        </Tooltip>
      );
    }

    return disabled;
  }

  const link = (
    <Link href={item.href} className={className} onClick={onNavigate}>
      {content}
    </Link>
  );

  if (collapsed) {
    return (
      <Tooltip>
        <TooltipTrigger render={link} />
        <TooltipContent side="right">{item.label}</TooltipContent>
      </Tooltip>
    );
  }

  return link;
}

export function SidebarNav({ sections, onNavigate }: SidebarNavProps) {
  const pathname = usePathname();
  const { collapsed } = useSidebar();

  return (
    <ScrollArea className="flex-1 px-2">
      <nav className="flex flex-col gap-6 py-2" aria-label="Main navigation">
        {sections.map((section) => (
          <div key={section.id} className="space-y-1">
            {section.label && !collapsed ? (
              <p className="px-3 pb-1 text-xs font-medium tracking-wide text-sidebar-foreground/50 uppercase">
                {section.label}
              </p>
            ) : null}
            <ul className="flex flex-col gap-0.5">
              {section.items.map((item) => (
                <li key={item.id}>
                  <NavLink
                    item={item}
                    collapsed={collapsed}
                    active={isNavItemActive(pathname, item.href)}
                    onNavigate={onNavigate}
                  />
                </li>
              ))}
            </ul>
          </div>
        ))}
      </nav>
    </ScrollArea>
  );
}
